import os
import json
import argparse
import heapq
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()

    for step in range(max_steps):
        try:
            neighbors = obs['neighbors']
            nodes = obs['nodes']
        except Exception:
            break
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            break
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        # Compute scores for all utility>0 nodes (global), excluding the start.
        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            score = u / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        chosen = None
        if scored:
            target_idx = scored[0][1]
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
        else:
            # No utility>0 reachable. Go to nearest unvisited node via shortest path.
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                chosen = neighbors[0]

        try:
            obs, info = env.step(chosen)
        except Exception as e:
            break
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path) as f:
                cfg = json.load(f)
            if isinstance(cfg, dict):
                episodes = cfg.get('episodes') or cfg.get('maps') or cfg.get('eval_maps') or []
            elif isinstance(cfg, list):
                episodes = cfg
        except Exception:
            episodes = []

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    # If no episodes from config, scan maps_eval directory
    if not episodes and os.path.isdir(maps_dir):
        for sub in sorted(os.listdir(maps_dir)):
            sd = os.path.join(maps_dir, sub)
            if os.path.isdir(sd):
                for fn in sorted(os.listdir(sd)):
                    if fn.lower().endswith(('.png', '.jpg', '.jpeg')):
                        episodes.append({'map_path': f'{sub}/{fn}', 'env_type': sub})

    per_episode = []
    per_type_acc = {}
    succ_total = 0
    dist_total = 0.0
    succ_count_dist = 0
    explored_total = 0.0
    n = 0
    for ep in episodes:
        mp = ep.get('map_path') if isinstance(ep, dict) else ep
        env_type = ep.get('env_type') if isinstance(ep, dict) else 'unknown'
        if not env_type and isinstance(mp, str):
            env_type = mp.split('/')[0]
        full_path = os.path.join(maps_dir, mp) if not os.path.isabs(mp) else mp
        try:
            metrics = plan_episode(full_path)
            er = float(metrics.get('explored_rate', 0.0))
            td = float(metrics.get('travel_distance', 0.0))
            sc = 1 if er > 0.9999 else 0
        except Exception as e:
            er, td, sc = 0.0, 0.0, 0

        per_episode.append({
            'map_path': mp,
            'env_type': env_type,
            'success': sc,
            'travel_distance': td,
            'explored_rate': er,
        })
        per_type_acc.setdefault(env_type, {'er': [], 'td': [], 'sc': []})
        per_type_acc[env_type]['er'].append(er)
        per_type_acc[env_type]['td'].append(td)
        per_type_acc[env_type]['sc'].append(sc)
        explored_total += er
        if sc == 1:
            dist_total += td
            succ_count_dist += 1
        succ_total += sc
        n += 1

    succ = succ_total / n if n > 0 else 0.0
    travel = dist_total / succ_count_dist if succ_count_dist > 0 else 0.0
    explored = explored_total / n if n > 0 else 0.0
    per_type = {}
    for k, v in per_type_acc.items():
        ns = sum(v['sc'])
        td_succ = [d for d, s in zip(v['td'], v['sc']) if s == 1]
        per_type[k] = {
            'explored_rate': float(np.mean(v['er'])) if v['er'] else 0.0,
            'travel_distance': float(np.mean(td_succ)) if td_succ else 0.0,
            'success_rate': float(np.mean(v['sc'])) if v['sc'] else 0.0,
        }
    out = {
        'explored_rate': explored,
        'travel_distance': travel,
        'success_rate': succ,
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': n,
    }
    with open(args.output, 'w') as f:
        json.dump(out, f, indent=2)
    print(f'Wrote {args.output}: succ={succ:.3f} dist={travel:.1f} explored={explored:.3f} n={n}')


if __name__ == '__main__':
    main()
